import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../api';

const AddProduct = () => {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [price, setPrice] = useState(0);
  const [category, setCategory] = useState('BOOKS');
  const [image, setImage] = useState(null);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const formData = new FormData();
      formData.append('title', title);
      formData.append('description', description);
      formData.append('price', price);
      formData.append('category', category);
      if (image) formData.append('image', image);

      await api.post('/products', formData, { headers: { 'Content-Type': 'multipart/form-data' } });
      navigate('/');
    } catch (err) {
      setError('Could not add product');
    }
  };

  return (
    <div>
      <h2>Add Product</h2>
      {error && <p style={{ color: 'red' }}>{error}</p>}
      <form onSubmit={handleSubmit}>
        <input value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Title" required />
        <textarea value={description} onChange={(e) => setDescription(e.target.value)} placeholder="Description" required />
        <input type="number" value={price} onChange={(e) => setPrice(e.target.value)} placeholder="Price" min="0" required />
        <select value={category} onChange={(e) => setCategory(e.target.value)}>
          <option value="BOOKS">Books</option>
          <option value="ELECTRONICS">Electronics</option>
          <option value="LAB_EQUIPMENT">Lab Equipment</option>
          <option value="HOSTEL_ESSENTIALS">Hostel Essentials</option>
          <option value="ACCESSORIES">Accessories</option>
          <option value="PROJECT_MATERIALS">Project Materials</option>
          <option value="OTHER">Other</option>
        </select>
        <input type="file" onChange={(e) => setImage(e.target.files?.[0] || null)} />
        <button type="submit">Add</button>
      </form>
    </div>
  );
};

export default AddProduct;
